c6739398852169362336 = 'package com.sujood.app.ui.screens.monetization\n\nimport androidx.compose.foundation.background\nimport androidx.compose.foundation.border\nimport androidx.compose.foundation.clickable\nimport androidx.compose.foundation.layout.*\nimport androidx.compose.foundation.rememberScrollState\nimport androidx.compose.foundation.shape.RoundedCornerShape\nimport androidx.compose.foundation.verticalScroll\nimport androidx.compose.material.icons.Icons\nimport androidx.compose.material.icons.filled.Check\nimport androidx.compose.material.icons.filled.Close\nimport androidx.compose.material3.*\nimport androidx.compose.runtime.Composable\nimport androidx.compose.runtime.rememberCoroutineScope\nimport androidx.compose.ui.Alignment\nimport androidx.compose.ui.Modifier\nimport androidx.compose.ui.draw.clip\nimport androidx.compose.ui.graphics.Brush\nimport androidx.compose.ui.graphics.Color\nimport androidx.compose.ui.text.font.FontWeight\nimport androidx.compose.ui.text.style.TextAlign\nimport androidx.compose.ui.unit.dp\nimport androidx.compose.ui.unit.sp\nimport com.sujood.app.data.local.datastore.UserPreferences\nimport com.sujood.app.ui.theme.DeepNavy\nimport com.sujood.app.ui.theme.TextSecondary\nimport com.sujood.app.ui.theme.TextTertiary\nimport kotlinx.coroutines.launch\n\n// Design tokens matching the mockup\nprivate val BgTop        = Color(0xFF0A0E1A)\nprivate val BgBottom     = Color(0xFF0D1230)\nprivate val CardBg       = Color(0xFF111827)\nprivate val CardBorder   = Color(0xFF1E2A45)\nprivate val PrimaryBlue  = Color(0xFF1E40FF)\nprivate val BlueBright   = Color(0xFF3B5BFF)\nprivate val MoonBlue     = Color(0xFF1E3A8A)\nprivate val CheckBg      = Color(0xFF1E3A6E)\nprivate val CheckColor   = Color(0xFF93C5FD)\n\n@Composable\nfun MonetizationScreen(\n    userPreferences: UserPreferences,\n    onPrivacy: () -> Unit = {},\n    onTerms: () -> Unit = {},\n    onContinue: () -> Unit\n) {\n    val scope = rememberCoroutineScope()\n\n\n    Box(\n        modifier = Modifier\n            .fillMaxSize()\n            .background(\n                Brush.verticalGradient(listOf(BgTop, BgBottom))\n            )\n    ) {\n        Column(\n            modifier = Modifier\n                .fillMaxSize()\n                .verticalScroll(rememberScrollState())\n                .statusBarsPadding()\n                .navigationBarsPadding(),\n            horizontalAlignment = Alignment.CenterHorizontally\n        ) {\n\n            // ── Top bar ──────────────────────────────────────────────────────\n            Box(\n                modifier = Modifier\n                    .fillMaxWidth()\n                    .padding(horizontal = 20.dp, vertical = 16.dp)\n            ) {\n                // Close button\n                Box(\n                    modifier = Modifier\n                        .align(Alignment.CenterStart)\n                        .size(36.dp)\n                        .clip(RoundedCornerShape(10.dp))\n                        .background(Color.White.copy(alpha = 0.07f))\n                        .clickable {\n                            scope.launch {\n                                userPreferences.setOnboardingCompleted()\n                                onContinue()\n                            }\n                        },\n                    contentAlignment = Alignment.Center\n                ) {\n                    Icon(\n                        imageVector = Icons.Filled.Close,\n                        contentDescription = "Close",\n                        tint = Color.White.copy(alpha = 0.7f),\n                        modifier = Modifier.size(18.dp)\n                    )\n                }\n                // Title\n                Text(\n                    text = "SUJOOD PREMIUM",\n                    fontSize = 12.sp,\n                    fontWeight = FontWeight.SemiBold,\n                    letterSpacing = 2.sp,\n                    color = Color.White.copy(alpha = 0.6f),\n                    modifier = Modifier.align(Alignment.Center)\n                )\n            }\n\n            Spacer(Modifier.height(24.dp))\n\n            // ── App icon ─────────────────────────────────────────────────────\n            androidx.compose.foundation.Image(\n                painter = androidx.compose.ui.res.painterResource(id = com.sujood.app.R.mipmap.ic_launcher_image),\n                contentDescription = "Sujood",\n                modifier = Modifier\n                    .size(90.dp)\n                    .clip(RoundedCornerShape(24.dp))\n            )\n\n            Spacer(Modifier.height(32.dp))\n\n            // ── Headline ─────────────────────────────────────────────────────\n            Text(\n                text = "Unlock the Full\\nExperience",\n                fontSize = 32.sp,\n                fontWeight = FontWeight.Bold,\n                color = Color.White,\n                textAlign = TextAlign.Center,\n                lineHeight = 40.sp,\n                modifier = Modifier.padding(horizontal = 32.dp)\n            )\n\n            Spacer(Modifier.height(16.dp))\n\n            Text(\n                text = "Support local development and enjoy an ad-free experience while you focus on your prayers.",\n                fontSize = 15.sp,\n                color = TextSecondary,\n                textAlign = TextAlign.Center,\n                lineHeight = 22.sp,\n                modifier = Modifier.padding(horizontal = 40.dp)\n            )\n\n            Spacer(Modifier.height(36.dp))\n\n            // ── Premium card ─────────────────────────────────────────────────\n            Box(\n                modifier = Modifier\n                    .fillMaxWidth()\n                    .padding(horizontal = 20.dp)\n                    .clip(RoundedCornerShape(24.dp))\n                    .background(CardBg)\n                    .border(1.dp, CardBorder, RoundedCornerShape(24.dp))\n            ) {\n                Column(\n                    modifier = Modifier.padding(24.dp)\n                ) {\n                    // ONE-TIME badge top-right\n                    Row(\n                        modifier = Modifier.fillMaxWidth(),\n                        horizontalArrangement = Arrangement.End\n                    ) {\n                        Box(\n                            modifier = Modifier\n                                .clip(RoundedCornerShape(20.dp))\n                                .background(PrimaryBlue.copy(alpha = 0.15f))\n                                .border(1.dp, PrimaryBlue.copy(alpha = 0.4f), RoundedCornerShape(20.dp))\n                                .padding(horizontal = 12.dp, vertical = 5.dp)\n                        ) {\n                            Text(\n                                text = "ONE-TIME",\n                                fontSize = 11.sp,\n                                fontWeight = FontWeight.SemiBold,\n                                letterSpacing = 1.sp,\n                                color = CheckColor\n                            )\n                        }\n                    }\n\n                    Spacer(Modifier.height(12.dp))\n\n                    // Title + price\n                    Text(\n                        text = "Premium Supporter",\n                        fontSize = 22.sp,\n                        fontWeight = FontWeight.Bold,\n                        color = Color.White\n                    )\n\n                    Spacer(Modifier.height(8.dp))\n\n                    Row(verticalAlignment = Alignment.Bottom) {\n                        Text(\n                            text = "\\$2.99",\n                            fontSize = 40.sp,\n                            fontWeight = FontWeight.Bold,\n                            color = Color.White\n                        )\n                        Spacer(Modifier.width(6.dp))\n                        Text(\n                            text = "forever",\n                            fontSize = 15.sp,\n                            color = TextSecondary,\n                            modifier = Modifier.padding(bottom = 8.dp)\n                        )\n                    }\n\n                    Spacer(Modifier.height(24.dp))\n\n                    // Feature list\n                    listOf(\n                        "Ad-free forever",\n                        "Support local development",\n                        "Exclusive future features"\n                    ).forEach { feature ->\n                        Row(\n                            verticalAlignment = Alignment.CenterVertically,\n                            modifier = Modifier.padding(vertical = 10.dp)\n                        ) {\n                            Box(\n                                modifier = Modifier\n                                    .size(32.dp)\n                                    .clip(RoundedCornerShape(10.dp))\n                                    .background(CheckBg),\n                                contentAlignment = Alignment.Center\n                            ) {\n                                Icon(\n                                    imageVector = Icons.Filled.Check,\n                                    contentDescription = null,\n                                    tint = CheckColor,\n                                    modifier = Modifier.size(16.dp)\n                                )\n                            }\n                            Spacer(Modifier.width(16.dp))\n                            Text(\n                                text = feature,\n                                fontSize = 15.sp,\n                                color = Color.White.copy(alpha = 0.85f)\n                            )\n                        }\n                    }\n\n                    Spacer(Modifier.height(24.dp))\n\n                    // CTA button\n                    Box(\n                        modifier = Modifier\n                            .fillMaxWidth()\n                            .clip(RoundedCornerShape(50.dp))\n                            .background(\n                                Brush.horizontalGradient(\n                                    listOf(PrimaryBlue, BlueBright)\n                                )\n                            )\n                            .clickable {\n                                scope.launch {\n                                    userPreferences.setOnboardingCompleted()\n                                    onContinue()\n                                }\n                            }\n                            .padding(vertical = 18.dp),\n                        contentAlignment = Alignment.Center\n                    ) {\n                        Text(\n                            text = "Get Premium Access",\n                            fontSize = 16.sp,\n                            fontWeight = FontWeight.SemiBold,\n                            color = Color.White\n                        )\n                    }\n                }\n            }\n\n            Spacer(Modifier.height(28.dp))\n\n            // ── Skip link ────────────────────────────────────────────────────\n            Text(\n                text = "Continue with limited free version",\n                fontSize = 13.sp,\n                color = TextSecondary,\n                textDecoration = androidx.compose.ui.text.style.TextDecoration.Underline,\n                modifier = Modifier\n                    .clickable {\n                        scope.launch {\n                            userPreferences.setOnboardingCompleted()\n                            onContinue()\n                        }\n                    }\n                    .padding(8.dp)\n            )\n\n            Spacer(Modifier.height(20.dp))\n\n            // ── Footer links ─────────────────────────────────────────────\n            Row(\n                horizontalArrangement = Arrangement.spacedBy(24.dp),\n                modifier = Modifier.padding(bottom = 32.dp)\n            ) {\n                listOf(\n                    "Privacy Policy" to onPrivacy,\n                    "Terms of Service" to onTerms,\n                    "Restore Purchase" to ({})\n                ).forEach { (label, action) ->\n                    Text(\n                        text = label,\n                        fontSize = 11.sp,\n                        color = TextTertiary,\n                        modifier = Modifier.clickable { action() }\n                    )\n                }\n            }\n        }\n    }\n}\n'
